sql:
SELECT respondents.respondent_id, vaccination_history.vaccine_type
FROM respondents
INNER JOIN vaccination_history ON respondents.respondent_id = vaccination_history.respondent_id;

SELECT respondent_id
FROM opinions_h1n1
WHERE opinion_h1n1_trust = 5;

SELECT respondent_id
FROM respondents
WHERE respondent_id NOT IN (SELECT respondent_id FROM vaccination_history);

external_knowledge:
- 'travelers' refers to the respondents;
- 'green light from their captain' symbolizes a recommendation for the seasonal flu vaccine from a doctor;
- 'chose not to embark on the voyage' represents not receiving the seasonal flu vaccine.

sql:
SELECT respondent_id
FROM vaccination_history
WHERE doctor_recc_seasonal = 1 AND seasonal_vaccine = 0;

SELECT respondent_id, concern_knowledge_id, seasonal_concern
FROM concerns_and_knowledge
WHERE seasonal_concern = 1;

SELECT respondent_id, age_group, education, race, sex, income_poverty, marital_status, rent_or_own, employment_status, census_msa, household_adults, household_children, email, phone_number, date_of_birth, zip_code
FROM respondents
WHERE respondent_id = 1;

external_knowledge:
- "embarked on a journey" metaphorically refers to being part of the subset of respondents with specific characteristics;
- "eyes to see the true value" symbolizes having a positive opinion on the vaccine's effectiveness (opinion_seas_vacc_effective > 3);
- "taken the steps to protect themselves" refers to having received the seasonal flu vaccine;
- "unique identifiers, age groups, and ethnic backgrounds" correspond to the columns `respondent_id`, `age_group`, `race`.
